const raw = $input.first().json;
const body = (raw.body !== undefined) ? raw.body : raw;
if (!body.job_id) throw new Error('Payload missing: job_id');
if (!Array.isArray(body.clip_prompts) || body.clip_prompts.length === 0) throw new Error('Payload must have clip_prompts array with at least 1 entry');
return [{ json: {
  job_id: body.job_id,
  topic: body.topic,
  title: body.title,
  hashtags: body.hashtags,
  narration: body.narration,
  clip_prompts: body.clip_prompts,
  audio_path: body.audio_path,
  subs_path: body.subs_path,
  audio_duration: body.audio_duration,
  subtitle_chunks: body.subtitle_chunks,
  word_timings: body.word_timings || [],
  sheet_row: body.sheet_row || null,
  start_time: body.start_time || Date.now()
} }];

const { execSync } = require('child_process');
const fs = require('fs');

const data           = $input.first().json;
const jobId          = data.job_id;
const videoUrls      = data.video_urls;
const subtitleChunks = data.subtitle_chunks || [];
const audioDuration  = data.audio_duration || 30;
const wordTimings    = data.word_timings || [];
const N              = videoUrls.length;

const n8nIn   = '/data/ffmpeg/input';
const n8nOut  = '/data/ffmpeg/output';
const contIn  = '/ffmpeg/input';
const contOut = '/ffmpeg/output';

if (!fs.existsSync(n8nIn))  fs.mkdirSync(n8nIn,  { recursive: true });
if (!fs.existsSync(n8nOut)) fs.mkdirSync(n8nOut, { recursive: true });

function run(cmd, timeout) {
  let out = '';
  try { out = execSync(cmd, { encoding: 'utf-8', timeout: timeout || 120000 }); }
  catch(e) { out = ((e.stdout || '') + (e.stderr || '') + (e.message || '')).toString(); }
  return out;
}

console.log('Assembling ' + N + ' clips | audio: ' + audioDuration.toFixed(1) + 's');

// ── STEP 1: Download all clips ────────────────────────────────
for (let i = 0; i < N; i++) {
  const dest = contIn + '/' + jobId + '_clip' + i + '.mp4';
  console.log('Downloading clip ' + (i+1) + '/' + N + '...');
  const out = run(
    'docker exec ffmpeg-runner curl -sL --max-time 90 -o "' + dest + '" "' + videoUrls[i] + '" && echo DL_OK',
    100000
  );
  if (!out.includes('DL_OK'))
    throw new Error('Clip ' + i + ' download failed: ' + out.slice(-200));
}
console.log('All clips downloaded');

// ── STEP 2: Normalize each clip to 1080x1920 (9:16) ──────────
// Pad with black bars if aspect ratio differs — keeps full content
for (let i = 0; i < N; i++) {
  const src  = contIn  + '/' + jobId + '_clip' + i + '.mp4';
  const norm = contIn  + '/' + jobId + '_clip' + i + '_norm.mp4';
  const out  = run(
    'docker exec ffmpeg-runner ffmpeg -y -i "' + src + '" ' +
    '-vf "scale=1080:1920:force_original_aspect_ratio=decrease,' +
         'pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black" ' +
    '-r 24 -c:v libx264 -crf 20 -preset fast -an "' + norm + '" 2>&1 && echo NORM_OK',
    180000
  );
  if (!out.includes('NORM_OK'))
    throw new Error('Normalize clip ' + i + ' failed: ' + out.slice(-300));
}
console.log('All clips normalized to 1080x1920 @ 24fps');

// ── STEP 3: Concat with XFADE transitions ────────────────────
// xfade creates smooth crossfade between consecutive clips.
// Fade duration = 0.3s. CLIP_DUR comes from Submit Clips node (always 5).
// Offset = i * (CLIP_DUR - 0.3)  (where the next clip starts blending)
const FADE_DUR = 0.3;
const CLIP_DUR = data.clip_dur || 5;
const NET      = CLIP_DUR - FADE_DUR;   // effective duration per clip before fade
console.log('CLIP_DUR=' + CLIP_DUR + 's (from payload), FADE_DUR=' + FADE_DUR + 's, NET=' + NET + 's');

let withTransitions;

if (N === 1) {
  // Single clip — no transitions needed
  withTransitions = contIn + '/' + jobId + '_clip0_norm.mp4';
  console.log('Single clip, skipping xfade');
} else {
  // Build -filter_complex xfade chain:
  // [0:v][1:v]xfade=fade:0.5:9.5[x1];[x1][2:v]xfade=fade:0.5:19.0[x2];...
  const inputs  = Array.from({ length: N }, (_, i) =>
    '-i "' + contIn + '/' + jobId + '_clip' + i + '_norm.mp4"'
  ).join(' ');

  let filterParts = [];
  let prevLabel   = '[0:v]';
  for (let i = 1; i < N; i++) {
    const offset   = (i * NET).toFixed(1);
    const outLabel = (i === N - 1) ? '[vout]' : '[x' + i + ']';
    filterParts.push(prevLabel + '[' + i + ':v]xfade=transition=fade:duration=' + FADE_DUR + ':offset=' + offset + outLabel);
    prevLabel = outLabel;
  }
  const filterComplex = filterParts.join('; ');

  const xfadeOut = contIn + '/' + jobId + '_xfade.mp4';
  const xfadeCmd =
    'docker exec ffmpeg-runner ffmpeg -y ' + inputs + ' ' +
    '-filter_complex "' + filterComplex + '" ' +
    '-map "[vout]" -c:v libx264 -crf 20 -preset fast "' + xfadeOut + '" 2>&1 && echo XFADE_OK';

  console.log('Building xfade for ' + N + ' clips...');
  const out = run(xfadeCmd, 600000);
  if (!out.includes('XFADE_OK'))
    throw new Error('xfade failed: ' + out.slice(-500));
  withTransitions = xfadeOut;
  console.log('xfade complete');
}

// ── STEP 4: Write ASS subtitle file ────────────────────────────────
function toAssTime(sec) {
  const h  = Math.floor(sec / 3600);
  const m  = Math.floor((sec % 3600) / 60);
  const s  = Math.floor(sec % 60);
  const cs = Math.round((sec % 1) * 100);
  const pad2 = n => String(n).padStart(2, '0');
  return h + ':' + pad2(m) + ':' + pad2(s) + '.' + pad2(cs);
}

const assHeader =
  '[Script Info]\n' +
  'ScriptType: v4.00+\n' +
  'PlayResX: 1080\n' +
  'PlayResY: 1920\n' +
  'ScaledBorderAndShadow: yes\n' +
  '\n' +
  '[V4+ Styles]\n' +
  'Format: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, Underline, StrikeOut, ScaleX, ScaleY, Spacing, Angle, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding\n' +
  'Style: Default,Arial,72,&H00FFFFFF,&H000000FF,&H00000000,&HAA000000,1,0,0,0,100,100,0,0,4,0,1,2,40,40,180,1\n' +
  '\n' +
  '[Events]\n' +
  'Format: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text\n';

let assEvents = '';

if (wordTimings.length > 0) {
  for (let g = 0; g < wordTimings.length; g += 3) {
    const group = wordTimings.slice(g, g + 3);
    const nextGroupStart = (wordTimings[g + 3]) ? wordTimings[g + 3].start : null;

    for (let w = 0; w < group.length; w++) {
      const word = group[w];
      const nextWord = group[w + 1];

      let evEnd;
      if (nextWord) {
        evEnd = nextWord.start;
      } else {
        evEnd = word.end + 0.15;
        if (nextGroupStart && evEnd > nextGroupStart) evEnd = nextGroupStart;
      }

      let text = '';
      for (let i = 0; i < group.length; i++) {
        if (i > 0) text += ' ';
        if (i === w) {
          text += '{\\c&H0000FFFF&}' + group[i].text.toUpperCase() + '{\\c&H00FFFFFF&}';
        } else {
          text += group[i].text.toUpperCase();
        }
      }

      assEvents += 'Dialogue: 0,' + toAssTime(word.start) + ',' + toAssTime(evEnd) +
                   ',Default,,0,0,0,,' + text + '\n';
    }
  }
} else {
  for (let i = 0; i < subtitleChunks.length; i++) {
    const c = subtitleChunks[i];
    assEvents += 'Dialogue: 0,' + toAssTime(c.start) + ',' + toAssTime(c.end) +
                 ',Default,,0,0,0,,' + c.text.toUpperCase() + '\n';
  }
}

const assContent = assHeader + assEvents;
const assN8nPath = n8nIn + '/' + jobId + '.ass';
const assContPath = contIn + '/' + jobId + '.ass';
fs.writeFileSync(assN8nPath, assContent, 'utf-8');
console.log('ASS file saved: ' + assN8nPath + ' (' + assEvents.split('\n').filter(Boolean).length + ' events)');

// ── STEP 5: Final — video + narration audio + burned ASS subtitles ─
const audioContPath = contIn + '/' + jobId + '_narration.mp3';
const finalContPath = contOut + '/' + jobId + '_final.mp4';

const finalCmd =
  'docker exec ffmpeg-runner ffmpeg -y ' +
  '-i "' + withTransitions + '" ' +
  '-i "' + audioContPath + '" ' +
  '-vf "ass=\'' + assContPath + '\'" ' +
  '-c:v libx264 -crf 20 -preset fast ' +
  '-c:a aac -b:a 128k ' +
  '-movflags +faststart ' +
  '-shortest ' +
  '"' + finalContPath + '" 2>&1 && echo FINAL_OK';

console.log('Running final assembly...');
const finalOut = run(finalCmd, 900000);
if (!finalOut.includes('FINAL_OK'))
  throw new Error('Final assembly failed: ' + finalOut.slice(-600));

const n8nFinalPath = n8nOut + '/' + jobId + '_final.mp4';
if (!fs.existsSync(n8nFinalPath))
  throw new Error('Final video missing: ' + n8nFinalPath);

console.log('Done! Final video: ' + n8nFinalPath);

return [{ json: {
  ...data,
  output_filename:  jobId + '_final.mp4',
  final_video_path: n8nFinalPath,
  clips_used:       N,
  audio_duration:   audioDuration
}}];

const fs = require('fs');
const item = $input.first().json;
const filePath = item.final_video_path;

if (!fs.existsSync(filePath)) {
  throw new Error('Final video not found at: ' + filePath);
}

const buffer = fs.readFileSync(filePath);

return [{
  json: item,
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'video/mp4',
      fileName: item.output_filename,
      fileExtension: 'mp4'
    }
  }
}];

const driveNode   = $('Upload Animation to Drive').first().json;
const assembleData = $('Assemble Video').first().json;
const extractData  = $('Extract Payload').first().json;
const fileId = driveNode.id;

const videoUrl       = 'https://drive.google.com/uc?export=download&id=' + fileId;
const renderTimeSec  = Math.round((Date.now() - assembleData.start_time) / 1000);

console.log('Stage 2 complete. Job: ' + assembleData.job_id + ', Drive file: ' + fileId + ', Time: ' + renderTimeSec + 's');

return [{ json: {
  job_id:             assembleData.job_id,
  topic:              assembleData.topic,
  title:              assembleData.title,
  video_url:          videoUrl,
  drive_file_id:      fileId,
  render_time_seconds: renderTimeSec,
  sheet_row:          extractData.sheet_row,
  status:             'stage2_complete'
} }];

const https = require('https');
const data = $input.first().json;
const apiKey = $env.WAVESPEED_API_KEY;
const clipPrompts = data.clip_prompts;

if (!Array.isArray(clipPrompts) || clipPrompts.length === 0)
  throw new Error('No clip_prompts in payload');

// Determine how many clips we need based on audio duration
const audioDuration = data.audio_duration || 25;
const clipsNeeded   = Math.min(clipPrompts.length, Math.max(2, Math.ceil(audioDuration / 5)));

const clipDur = 5;
console.log('Audio duration: ' + audioDuration.toFixed(1) + 's | ' + clipsNeeded + ' clips | clip duration: ' + clipDur + 's');

function apiPost(body) {
  return new Promise((resolve, reject) => {
    const buf = Buffer.from(JSON.stringify(body));
    const req = https.request({
      hostname: 'api.wavespeed.ai',
      path: '/api/v3/bytedance/seedance-v1-lite-t2v-720p',
      method: 'POST',
      headers: {
        'Authorization': 'Bearer ' + apiKey,
        'Content-Type': 'application/json',
        'Content-Length': buf.length
      }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
        catch(e) { reject(new Error('Bad JSON from Wavespeed: ' + Buffer.concat(chunks).toString().slice(0,200))); }
      });
    });
    req.on('error', reject);
    req.write(buf);
    req.end();
  });
}

// Submit clips in parallel (faster than sequential)
const submitPromises = [];
for (let i = 0; i < clipsNeeded; i++) {
  console.log('Submitting clip ' + (i+1) + '/' + clipsNeeded + ' (duration=' + clipDur + 's)...');
  console.log('  Prompt: ' + clipPrompts[i].slice(0, 100) + '...');
  submitPromises.push(
    apiPost({
      prompt:          (p => p.length <= 450 ? p : p.slice(0, p.lastIndexOf(' ', 450)))(clipPrompts[i]),
      aspect_ratio:    '9:16',
      duration:        5,
      seed:            -1
    })
  );
}

const results = await Promise.all(submitPromises);

const task_ids = [];
for (let i = 0; i < results.length; i++) {
  const r = results[i];
  if (!r.data || !r.data.id)
    throw new Error('Wavespeed submit failed clip ' + i + ': ' + JSON.stringify(r));
  task_ids.push(r.data.id);
  console.log('Clip ' + (i+1) + ' submitted — task id: ' + r.data.id);
}

console.log('All ' + clipsNeeded + ' clips submitted in parallel. clip_dur=' + clipDur + 's. Waiting for generation...');

return [{ json: {
  ...data,
  task_ids,
  clips_count:  clipsNeeded,
  clip_dur:     clipDur,
  video_urls:   new Array(clipsNeeded).fill(null),
  poll_attempt: 0,
  all_done:     false
}}];

const https = require('https');
const data = $input.first().json;
const apiKey = $env.WAVESPEED_API_KEY;
const task_ids   = data.task_ids;
const video_urls = [...(data.video_urls || [null, null, null])];
const attempt    = (data.poll_attempt || 0) + 1;

console.log('--- Poll attempt #' + attempt + ' ---');

function apiGet(taskId) {
  return new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'api.wavespeed.ai',
      path: '/api/v3/predictions/' + taskId + '/result',
      method: 'GET',
      headers: { 'Authorization': 'Bearer ' + apiKey }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const raw = Buffer.concat(chunks).toString();
        try { resolve(JSON.parse(raw)); }
        catch(e) { reject(new Error('Non-JSON from Wavespeed status [HTTP ' + res.statusCode + ']: ' + raw.slice(0,200))); }
      });
    });
    req.on('error', reject);
    req.end();
  });
}

// Check each clip that is not yet complete
for (let i = 0; i < task_ids.length; i++) {
  if (video_urls[i] !== null) {
    console.log('Clip ' + i + ' already done, skipping');
    continue;
  }

  const r = await apiGet(task_ids[i]);
  const status = (r.data && r.data.status) || 'unknown';
  console.log('Clip ' + i + ' [' + task_ids[i] + '] status: ' + status);

  if (status === 'succeeded' || status === 'completed') {
    const url = r.data.outputs && r.data.outputs[0];
    if (!url) throw new Error('Clip ' + i + ' done but output URL missing. status=' + status + ' resp=' + JSON.stringify(r.data).slice(0,300));
    video_urls[i] = url;
    console.log('Clip ' + i + ' ready: ' + url);
  } else if (status === 'failed') {
    throw new Error('Clip ' + i + ' FAILED: ' + JSON.stringify(r.data));
  } else {
    console.log('Clip ' + i + ' still ' + status + ' — will retry in 20s');
  }
}

const pending_count = video_urls.filter(u => u === null).length;
const clips_status = pending_count === 0 ? 'done' : 'waiting';

if (clips_status === 'done') {
  console.log('All clips ready! clips_status=done — proceeding to assembly.');
} else {
  console.log(pending_count + ' clip(s) still generating. clips_status=waiting.');
}

return [{ json: {
  ...data,
  task_ids,
  video_urls,
  poll_attempt: attempt,
  pending_count,
  clips_status
}}];
